def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness = (np.mean((positive_bins - avg_capacity)**3) / (np.std(positive_bins)**3)) if positive_bins.size > 2 else 0
    kurtosis = (np.mean((positive_bins - avg_capacity)**4) / (np.var(positive_bins)**2)) if positive_bins.size > 3 else 3
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        base_score = 0
        if ratio == 1:
            base_score = 0
        elif ratio > 0.9:
            base_score = ((1 - ratio) ** 6) * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            base_score = np.log1p(1/(1+np.exp(-20*(ratio-0.8))))*1.2 + 0.15
        elif 0.4 < ratio <= 0.7:
            base_score = 0
            for k in range(1, 15):
                term = ((-1)**k)*(ratio**(2*k)) / (k*0.9)
                base_score += term
            base_score = abs(base_score) + 0.12
        elif 0.15 < ratio <= 0.4:
            base_score = 0
            for p in range(1, 20):
                weight = 1 / (p ** 1.1)
                base_score += ((-1)**(p+1)) * (ratio**(p+2)) * weight
            base_score = abs(base_score) + 0.13
        else:
            base_score = 0.2 + 1/(1+np.exp(50*(ratio-0.1)))
        neighbors_influence = 0.0
        neighbors_weight_sum = 0.0
        for offset in range(1, 11):
            neighbor_caps = []
            if i - offset >= 0:
                neighbor_caps.append(bins[i - offset])
            if i + offset < n:
                neighbor_caps.append(bins[i + offset])
            for nc in neighbor_caps:
                if nc > 0:
                    diff = abs(capacity - nc)
                    norm_diff = diff / max(capacity, nc)
                    weight = 1 / (offset ** 2.5)
                    influence = norm_diff * weight
                    if nc > avg_capacity + variance * 1.5:
                        influence *= 1.15 + skewness * 0.2
                    elif nc < avg_capacity - variance * 1.5:
                        influence *= 0.85 - kurtosis * 0.1
                    neighbors_influence += influence
                    neighbors_weight_sum += weight
        if neighbors_weight_sum > 0:
            neighbors_influence /= neighbors_weight_sum
        cap_factor = (capacity ** 0.75) + (avg_capacity ** 0.25)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity)**4)*0.35
        elif capacity > item * 2.5:
            penalty = 0.06 + 0.01 * kurtosis
        if i % 3 == 0 and i % 5 == 0:
            base_score *= 0.7 + 0.05 * skewness
            neighbors_influence *= 1.3 - 0.02 * kurtosis
            penalty *= 1.15
        elif i % 6 == 0:
            base_score *= 1.12 - 0.03 * skewness
            neighbors_influence *= 0.88 + 0.04 * kurtosis
        elif i % 7 == 0:
            base_score *= 0.9
            neighbors_influence *= 1.1
        volatility_factor = 0
        for j in range(max(0, i-3), min(n, i+4)):
            if j != i and bins[j] > 0:
                volatility_factor += abs(bins[j] - capacity) / (capacity + 1)
        volatility_factor /= 6
        priority = base_score + neighbors_influence / (cap_factor + volatility_factor * 0.5) + penalty + volatility_factor * 0.07
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    threshold = np.percentile(finite_priorities, 90)
    for i in range(n):
        if priorities[i] < threshold * 0.5 and bins[i] > avg_capacity:
            priorities[i] *= 0.7 + 0.1 * np.sin(i)
        elif priorities[i] > threshold * 1.5 and bins[i] < avg_capacity:
            priorities[i] *= 1.1 - 0.05 * np.cos(i)
    return priorities
